59	const queryClient = new QueryClient();
60	
61	// AppContent lives inside BrowserRouter so routing hooks are available.
62	// useInitializeE2EE is called HERE — at the very top of this component,
63	// before any conditional returns — so React's rules of hooks are never violated.
64	function AppContent() {
65	  const [userId, setUserId] = useState("");
66	
67	  // MUST be called before any early returns.
68	  // Receives "" until the auth state resolves, then fires the full init flow.
69	  const {
70	    error: e2eeError,
71	    needsRecoveryPassword,
72	    needsMigration,
73	    provideRecoveryPassword,
74	    clearMigrationFlag,
75	  } = useInitializeE2EE(userId);
76	
77	  const [migrationDialogOpen, setMigrationDialogOpen] = useState(false);
78	
79	  // Open the migration dialog as soon as the flag is raised, but only once per session.
80	  useEffect(() => {
81	    if (needsMigration) setMigrationDialogOpen(true);
82	  }, [needsMigration]);
83	
84	  useEffect(() => {
85	    // onAuthStateChange fires immediately with the current session
86	    // (INITIAL_SESSION event) AND fires again on every sign-in / sign-out.
87	    // This is more reliable than getSession() which can return null on the
88	    // first tick in OAuth / server-redirect flows.
89	    const {
90	      data: { subscription },
91	    } = supabase.auth.onAuthStateChange((_event, session) => {
92	      setUserId(session?.user?.id ?? "");
93	    });
94	
95	    return () => subscription.unsubscribe();
96	  }, []);
97	
98	  return (
99	    <>
100	      <ScrollToTop />
101	      <CookieConsent />
102	
103	      {/* Non-dismissible: shown on a new device when a v2 backup exists */}
104	      <RecoveryPasswordModal
105	        open={needsRecoveryPassword}
106	        error={e2eeError}
107	        onSubmit={provideRecoveryPassword}
108	      />
109	
110	      {/* Dismissible: nudges v1 users and new users to set a recovery password */}
111	      <SetRecoveryPasswordDialog
112	        open={migrationDialogOpen}
113	        userId={userId}
114	        onOpenChange={setMigrationDialogOpen}
115	        onComplete={clearMigrationFlag}
116	      />
117	
118	      <Suspense fallback={<PageLoader />}>
119	        <Routes>
120	          {/* Public routes */}
121	          <Route path="/" element={<PublicPageWrapper><Home /></PublicPageWrapper>} />
122	          <Route path="/auth" element={<PublicPageWrapper><Auth /></PublicPageWrapper>} />
123	          <Route path="/auth/callback" element={<AuthCallback />} />
124	          <Route path="/reset-password" element={<PublicPageWrapper><ResetPassword /></PublicPageWrapper>} />
125	          <Route path="/pricing" element={<PublicPageWrapper><Pricing /></PublicPageWrapper>} />
126	          <Route path="/about" element={<PublicPageWrapper><About /></PublicPageWrapper>} />
127	          <Route path="/app/about" element={<AppLayout><About isEmbedded /></AppLayout>} />
128	          <Route path="/privacy-policy" element={<AppLayout><PrivacyPolicy /></AppLayout>} />
129	          <Route path="/terms-of-service" element={<AppLayout><TermsOfService /></AppLayout>} />
130	          <Route path="/cookie-policy" element={<AppLayout><CookiePolicy /></AppLayout>} />
131	          <Route path="/user-type-selection" element={<Navigate to="/auth" replace />} />
132	          <Route path="/signup/creator" element={<Navigate to="/auth?mode=signup" replace />} />
133	          <Route path="/signup/brand" element={<Navigate to="/auth?mode=signup" replace />} />
134	          <Route path="/:username" element={<PublicPageWrapper><PublicProfile /></PublicPageWrapper>} />
135	
136	          {/* Protected routes */}
137	          <Route path="/dashboard" element={<Navigate to="/kira" replace />} />
138	          <Route path="/kira" element={<ProtectedRoute><AppLayout><Kira /></AppLayout></ProtectedRoute>} />
139	          <Route path="/crevia-link" element={<ProtectedRoute><AppLayout><CreviaLink /></AppLayout></ProtectedRoute>} />
140	          <Route path="/crevia-studio" element={<ProtectedRoute><AppLayout><CreviaStudio /></AppLayout></ProtectedRoute>} />
141	          <Route path="/crevia-invoice" element={<ProtectedRoute><AppLayout><CreviaInvoice /></AppLayout></ProtectedRoute>} />
142	          <Route path="/crevia-contracts" element={<ProtectedRoute><AppLayout><CreviaContracts /></AppLayout></ProtectedRoute>} />
143	          <Route path="/mfa-verify" element={<MFAVerify />} />
144	          <Route path="/crevia-workspace" element={<ProtectedRoute><AppLayout><WorkspacesList /></AppLayout></ProtectedRoute>} />
145	          <Route path="/crevia-workspace/:id" element={<ProtectedRoute><AppLayout><WorkspacePage /></AppLayout></ProtectedRoute>} />
146	          <Route path="/invite/:token" element={<WorkspaceInvitePage />} />
147	          <Route path="/received" element={<ProtectedRoute><AppLayout><ReceivedDocuments /></AppLayout></ProtectedRoute>} />
148	          <Route path="/profile/payments-billing" element={<ProtectedRoute><AppLayout><PaymentsBilling /></AppLayout></ProtectedRoute>} />
149	          <Route path="/profile/notifications" element={<ProtectedRoute><AppLayout><Notifications /></AppLayout></ProtectedRoute>} />
150	          <Route path="/profile/verification" element={<ProtectedRoute><AppLayout><Verification /></AppLayout></ProtectedRoute>} />
151	          <Route path="/profile/settings" element={<ProtectedRoute><AppLayout><Settings /></AppLayout></ProtectedRoute>} />
152	          <Route path="/profile/help" element={<ProtectedRoute><AppLayout><Help /></AppLayout></ProtectedRoute>} />
153	          <Route path="/profile/feedback" element={<ProtectedRoute><AppLayout><Feedback /></AppLayout></ProtectedRoute>} />
154	          <Route path="/admin" element={<ProtectedRoute><AppLayout><Admin /></AppLayout></ProtectedRoute>} />
155	
156	          <Route path="*" element={<NotFound />} />
157	        </Routes>
158	      </Suspense>
159	    </>
160	  );
161	}
162	
163	const App = () => (
164	  <ErrorBoundary>
165	    <QueryClientProvider client={queryClient}>
166	      <ThemeProvider attribute="class" defaultTheme="light" enableSystem={false} storageKey="theme">
167	        <LanguageProvider>
168	          <TooltipProvider>
169	            <Toaster />
170	            <Sonner />
171	            <BrowserRouter>
172	              <AppContent />
173	            </BrowserRouter>
174	          </TooltipProvider>
175	        </LanguageProvider>
176	      </ThemeProvider>
177	    </QueryClientProvider>
178	  </ErrorBoundary>
179	);
180	
181	export default App;
